 19	function buildCurrentArtifacts(args: {
 20	  artifacts: ArtifactSummary[];
 21	  currentMaterialRefs: CurrentProcessMaterialRefs;
 22	  processId: string;
 23	}): ProcessArtifactReference[] {
 24	  const currentArtifactIds = new Set(args.currentMaterialRefs.artifactIds);
 25	
 26	  return sortByUpdatedAtDesc(
 27	    args.artifacts.filter((artifact) => currentArtifactIds.has(artifact.artifactId)),
 28	  ).map((artifact) => ({
 29	    artifactId: artifact.artifactId,
 30	    displayName: artifact.displayName,
 31	    currentVersionLabel: artifact.currentVersionLabel,
 32	    roleLabel: resolveArtifactRoleLabel(artifact, args.processId),
 33	    updatedAt: artifact.updatedAt,
 34	  }));
 35	}
 36	
 37	function resolveArtifactRoleLabel(artifact: ArtifactSummary, processId: string): string | null {
 38	  if (artifact.attachmentScope === 'project') {
 39	    return 'Current shared artifact';
 40	  }
 41	
 42	  if (artifact.processId === processId) {
 43	    return 'Current working artifact';
 44	  }
 45	
 46	  return 'Current referenced artifact';
 47	}
 48	
 49	function buildCurrentOutputs(args: {
 50	  outputs: PlatformProcessOutputSummary[];
 51	  currentArtifacts: ProcessArtifactReference[];
 52	}): ProcessOutputReference[] {
 53	  const currentArtifactIds = new Set(args.currentArtifacts.map((artifact) => artifact.artifactId));
 54	
 55	  return sortByUpdatedAtDesc(args.outputs)
 56	    .filter((output) => {
 57	      if (output.state !== 'published_to_artifact') {
 58	        return true;
 59	      }
 60	
 61	      if (output.linkedArtifactId === null) {
 62	        return true;
 63	      }
 64	
 65	      return !currentArtifactIds.has(output.linkedArtifactId);
 66	    })
 67	    .map((output) => ({
 68	      outputId: output.outputId,
 69	      displayName: output.displayName,
 70	      revisionLabel: output.revisionLabel,
 71	      state: output.state,
 72	      updatedAt: output.updatedAt,
 73	    }));
 74	}
 75	
 76	function buildCurrentSources(args: {
 77	  sourceAttachments: Awaited<ReturnType<PlatformStore['listProjectSourceAttachments']>>;
 78	  currentMaterialRefs: CurrentProcessMaterialRefs;
 79	}): ProcessSourceReference[] {
 80	  const currentSourceAttachmentIds = new Set(args.currentMaterialRefs.sourceAttachmentIds);
 81	
 82	  return sortByUpdatedAtDesc(
 83	    args.sourceAttachments.filter((sourceAttachment) =>
 84	      currentSourceAttachmentIds.has(sourceAttachment.sourceAttachmentId),
 85	    ),
 86	  ).map((sourceAttachment) => ({
 87	    sourceAttachmentId: sourceAttachment.sourceAttachmentId,
 88	    displayName: sourceAttachment.displayName,
 89	    purpose: sourceAttachment.purpose,
 90	    targetRef: sourceAttachment.targetRef,
 91	    hydrationState: sourceAttachment.hydrationState,
 92	    updatedAt: sourceAttachment.updatedAt,
 93	  }));
 94	}
