103	    const [artifacts, outputs, sourceAttachments, currentMaterialRefs] = await Promise.all([
104	      this.platformStore.listProjectArtifacts({
105	        projectId: args.projectId,
106	      }),
107	      this.platformStore.listProcessOutputs({
