  4	function appendSubsection(args: {
  5	  section: HTMLElement;
  6	  heading: string;
  7	  items: HTMLElement[];
  8	  emptyMessage: string;
  9	  targetDocument: Document;
 10	}): void {
 11	  const heading = args.targetDocument.createElement('h3');
 12	  heading.textContent = args.heading;
 13	  args.section.append(heading);
 14	
 15	  if (args.items.length === 0) {
 16	    const empty = args.targetDocument.createElement('p');
 17	    empty.textContent = args.emptyMessage;
 18	    args.section.append(empty);
 19	    return;
 20	  }
 21	
 22	  const list = args.targetDocument.createElement('ul');
 23	
 24	  for (const item of args.items) {
 25	    list.append(item);
 26	  }
 27	
 28	  args.section.append(list);
 29	}
