 46	export function renderProcessMaterialsSection(args: {
 47	  envelope: ProcessMaterialsSectionEnvelope | null;
 48	  targetDocument: Document;
 49	}): HTMLElement {
 50	  const section = createSectionElement({
 51	    title: 'Current materials',
 52	    targetDocument: args.targetDocument,
 53	  });
 54	  section.setAttribute('data-process-materials-section', 'true');
 55	
 56	  if (args.envelope === null) {
 57	    return appendSectionMessage({
 58	      section,
 59	      message: 'Loading current materials...',
 60	      targetDocument: args.targetDocument,
 61	    });
 62	  }
 63	
 64	  if (args.envelope.status === 'empty') {
 65	    return appendSectionMessage({
 66	      section,
 67	      message: 'No current materials apply right now.',
 68	      targetDocument: args.targetDocument,
 69	    });
 70	  }
 71	
 72	  if (args.envelope.status === 'error') {
 73	    return appendSectionMessage({
 74	      section,
 75	      message: args.envelope.error?.message ?? 'Current materials failed to load.',
 76	      targetDocument: args.targetDocument,
