257	  private transitionProcessToRunning(processId: string): ProcessActionStoreResult {
258	    for (const [projectId, processes] of this.processesByProjectId.entries()) {
259	      const index = processes.findIndex((process) => process.processId === processId);
260	
261	      if (index === -1) {
262	        continue;
263	      }
264	
265	      const existing = processes[index];
266	
267	      if (existing === undefined) {
268	        continue;
269	      }
270	
271	      const now = new Date().toISOString();
272	      const nextProcess = processSummarySchema.parse({
273	        ...existing,
274	        status: 'running',
275	        phaseLabel: existing.phaseLabel === 'Draft' ? 'Working' : existing.phaseLabel,
276	        nextActionLabel: 'Monitor progress in the work surface',
277	        availableActions: ['open', 'review'],
278	        updatedAt: now,
279	      });
280	      const nextProcesses = [...processes];
281	      nextProcesses[index] = nextProcess;
282	      this.processesByProjectId.set(projectId, nextProcesses);
283	
284	      return {
285	        process: nextProcess,
286	        currentRequest: null,
287	      };
288	    }
289	
290	    throw new Error(`Unknown process ${processId}`);
291	  }
